#!/bin/bash
# One-liner curl test for skip_nulls query

curl -s -X POST 'http://localhost:3000/query/dsl' -H 'Content-Type: application/json' -d '{"query":"{\"from\":{\"source_file\":\"shopify_feather_place_products.json\",\"alias\":\"shopify\"},\"joins\":[{\"source\":{\"source_file\":\"gmc_feather_place_products.json\",\"alias\":\"gmc\"},\"on\":{\"left\":\"shopify.variant.barcode\",\"right\":\"gmc.gtin\"},\"join_type\":\"left\",\"skip_nulls\":true}],\"select\":[{\"expr\":\"shopify.variant.barcode\",\"alias\":\"Shopify_Barcode\"},{\"expr\":\"shopify.variant.sku\",\"alias\":\"Shopify_SKU\"},{\"expr\":\"shopify.product.title\",\"alias\":\"Shopify_Product_Title\"},{\"expr\":\"shopify.product.handle\",\"alias\":\"Shopify_Handle\"},{\"expr\":\"shopify.variant.price\",\"alias\":\"Shopify_Price\"},{\"expr\":\"shopify.variant.inventoryQuantity\",\"alias\":\"Shopify_Inventory\"},{\"expr\":\"shopify.variant.metafield.value\",\"alias\":\"Shopify_MPN\"},{\"expr\":\"gmc.gtin\",\"alias\":\"GMC_GTIN\"},{\"expr\":\"gmc.mpn\",\"alias\":\"GMC_MPN\"},{\"expr\":\"gmc.title\",\"alias\":\"GMC_Title\"},{\"expr\":\"gmc.imageLink\",\"alias\":\"GMC_Image_URL\"},{\"expr\":\"gmc.offerId\",\"alias\":\"GMC_Offer_ID\"}],\"limit\":100000}","format":"json"}' | python3 -c "import sys,json; d=json.load(sys.stdin); rows=d.get('data',[]); print(f'Rows: {len(rows)}'); print(f'Matched: {sum(1 for r in rows if r.get(\"GMC_GTIN\"))}'); print(f'Unmatched: {sum(1 for r in rows if not r.get(\"GMC_GTIN\"))}')"
